/// <reference path="../../index.d.ts" />
import type { PublicLitElement as LitElement } from "@arcgis/lumina";
import type { Scale } from "../interfaces.js";

/** @deprecated Use the `calcite-swatch-group` and `calcite-swatch` components instead. */
export abstract class ColorPickerSwatch extends LitElement {
  /**
   * When `true`, the component is active.
   *
   * @default false
   */
  accessor active: boolean;
  /**
   * The color value.
   *
   * @see [Color CSS data type](https://developer.mozilla.org/en-US/docs/Web/CSS/color_value).
   */
  accessor color: string | null;
  /**
   * Specifies the size of the component.
   *
   * @default "m"
   */
  accessor scale: Scale;
}